onClick:
{{
  (async () => {
    try {
      // Validar checkbox de confirmación
      if (!Chk_entiendo_cancel.isChecked) {
        showAlert("Debes confirmar que entiendes la cancelación.", "warning");
        return;
      }

      // 1. Actualizar cobros
      const respCobros = await ZDescancelarFactura.run();

      if (!respCobros?.success) {
        showAlert("No fue posible actualizar los cobros.", "error");
        return;
      }

      // Espera breve para evitar errores de sincronización
      await new Promise(resolve => setTimeout(resolve, 800));

      // 2. Actualizar factura
      const respFactura = await ZUpdateEstatusFactura.run();

      if (!respFactura?.success) {
        showAlert("Los cobros se actualizaron, pero no fue posible actualizar la factura.", "error");
        return;
      }

      // Limpiar checkbox
      resetWidget("Chk_entiendo_cancel", true);

      // Cerrar modales
      closeModal("Modal_confirmar_cancelar");
      closeModal("Modal_Cancelar");

      showAlert("La factura fue descancelada correctamente.", "success");

      // Si quieres, aquí luego agregamos refresh de queries
      // await GetFacturas.run();
      // await GetCobros.run();

    } catch (e) {
      showAlert(`Error al descancelar la factura: ${e?.message || e}`, "error");
    }
  })()
}}
